"use strict";(self.webpackChunkexonumia_cc=self.webpackChunkexonumia_cc||[]).push([[91529],{20033:(a,n,e)=>{e.r(n),e.d(n,{data:()=>o});const o={key:"v-78734874",path:"/gha/twi/explain-bitcoin-like-im-five/",title:"Kyer…õkyer…õ bitcoin mu te s…õ nea madi mfe anum",lang:"twi",frontmatter:{supporters:[{name:"Undisclosed #1"}],translators:[{name:"Jeffrey Oa",href:"https://twitter.com/jeffrey_oa1"}]},excerpt:"",headers:[{level:3,title:"S…õ woda so ara ntumi nhu nea bitcoin y…õ a‚Ä¶",slug:"s…õ-woda-so-ara-ntumi-nhu-nea-bitcoin-y…õ-a",children:[]},{level:3,title:"Y…õnhw…õ nea esii no yiye:",slug:"y…õnhw…õ-nea-esii-no-yiye",children:[]},{level:3,title:"Y…õn san k…î ap…îw so!",slug:"y…õn-san-k…î-ap…îw-so",children:[]},{level:3,title:"L…õgya",slug:"l…õgya",children:[]},{level:3,title:"∆Ühaw ahorow",slug:"…îhaw-ahorow",children:[]},{level:3,title:"Ano aduru no",slug:"ano-aduru-no",children:[]},{level:3,title:"Mey…õ…õ nea …õy…õ mmer…õw kakra",slug:"mey…õ…õ-nea-…õy…õ-mmer…õw-kakra",children:[]}],filePathRelative:"gha/twi/explain-bitcoin-like-im-five/README.md",git:{updatedTime:1744187994e3}}},19819:(a,n,e)=>{e.r(n),e.d(n,{default:()=>c});var o=e(66252);const i=(0,o._)("h1",{id:"kyer…õkyer…õ-bitcoin-mu-te-s…õ-nea-madi-mfe-anum",tabindex:"-1"},[(0,o._)("a",{class:"header-anchor",href:"#kyer…õkyer…õ-bitcoin-mu-te-s…õ-nea-madi-mfe-anum","aria-hidden":"true"},"#"),(0,o.Uk)(" Kyer…õkyer…õ bitcoin mu te s…õ nea madi mfe anum")],-1),s=(0,o.Uk)("Nik Custodio na …îkyer…õwee "),m={href:"https://www.freecodecamp.org/news/explain-bitcoin-like-im-five-73b4257ac833/",target:"_blank",rel:"noopener noreferrer"},w=(0,o.Uk)("2013/12/12"),t=(0,o.uE)('<h3 id="s…õ-woda-so-ara-ntumi-nhu-nea-bitcoin-y…õ-a" tabindex="-1"><a class="header-anchor" href="#s…õ-woda-so-ara-ntumi-nhu-nea-bitcoin-y…õ-a" aria-hidden="true">#</a> S…õ woda so ara ntumi nhu nea bitcoin y…õ a‚Ä¶</h3><p>Y…õte benkyi bi a …õw…î ab…înten so. ∆êy…õ da k…õse.</p><p>Mew…î ap…îw baako w…î me nky…õn. Me de ma wo.</p><p>Afei wo w…î ap…îw baako …õna menni bi.</p><p>S…õ ano y…õ mmer…õw, …õnte saa?</p><h3 id="y…õnhw…õ-nea-esii-no-yiye" tabindex="-1"><a class="header-anchor" href="#y…õnhw…õ-nea-esii-no-yiye" aria-hidden="true">#</a> Y…õnhw…õ nea esii no yiye:</h3><p>W…îde m&#39;ap…îw hy…õ…õ wo nsam.</p><p>Wunim s…õ …õbaa saa. Na me w…î h…î. Na wo w…î h…î. Wode wo nsa kaa y…õ.</p><p>Na yenhia obi a …îto so abi…õsa w…î ha a …îb…õboa y…õn amane ade…õ nu. Na …õho nhia s…õ y…õtwe W…îfa Tommy a …îy…õ …îtemmufo a wagye din no ma …îne y…õn tena benkyi no so na …îsi so dua s…õ ap…îw no fii me nky…õn k…î…î wo nky…õn.</p><p>Ap…îw no y…õ wo dea! Me ntumi mma wo ap…îw foforo efis…õ minni bi a aka. Me nni tumi wo so bio. Ap…îw no gyaw m&#39;agyapade koraa. Wow…î ap…îwno so tumi koraa mprenmpren. Wubetumi de ama w&#39;adamfo no s…õ wop…õ a, na afei saa adamfo no betumi de ama n&#39;adamfo. Na nea …õkeka ho.</p><p>Enti saa na ankorankoro nsakrae te. Misusuw s…õ …õy…õ ade koro ankasa, s…õ ebia merema wo kwadu, nhoma, anaas…õ m…õka s…õ d…îla anan mu baako anaa d…îla bi‚Ä¶.</p><p>Nanso meredi m&#39;anim.</p><h3 id="y…õn-san-k…î-ap…îw-so" tabindex="-1"><a class="header-anchor" href="#y…õn-san-k…î-ap…îw-so" aria-hidden="true">#</a> Y…õn san k…î ap…îw so!</h3><p>Afei ka s…õ, mew…î dijitaal ap…îw baako. Gye, m…õma wo me dijitaal ap…îw.</p><p>Ah! Afei na ay…õ anika.</p><p>Wob…õy…õ d…õn ahu s…õ saa dijitaal ap…îw a kan no na …õy…õ me de no, afei …õy…õ wo dea, na wo nkutoo wo de? Dwen ho sekan baako.</p><p>∆êy…õ den k…õse, …õnte saa? Wob…õy…õ d…õn ahu s…õ mansoma saa ap…îw no ank…îma W…îfa Tommy s…õ email attachment kan? Anaa s…õ w&#39;adamfo Joe? Anaa s…õ m&#39;adamfo Lisa nso?</p><p>Ebiaa mey…õ…õ saa dijitaal ap…îw no bi kakra w…î me k…împuta no so. Ebiaa mede too intan…õt so na nnipa …îpepem baako twee.</p><p>S…õnea wuhu no, saa dijitaal nsakrae yi y…õ …îhaw kakra. Dijitaal ap…îw a wode b…õmane no nte s…õ nea wode honam fam ap…îw b…õmane.</p><p>K…împuta ho nyansahufo binom no w…î din a w…îde fr…õ …îhaw yi ankasa: w…îfr…õ no …îhaw a …õfa sika a w…îs…õe no mm…îho abien ho. Nanso mma …õnhaw wo w…î ho. Nea …õs…õ s…õ wuhu ara ne s…õ, ama w…în adwene atu afra bere tenten bi na wonsiesiee da.</p><p>∆êde besi nn…õ.</p><p>Nanso momma y…õmm…î mm…îden s…õ y…õn ankasa besusuw ano aduru ho.</p><h3 id="l…õgya" tabindex="-1"><a class="header-anchor" href="#l…õgya" aria-hidden="true">#</a> L…õgya</h3><p>Ebia …õs…õ s…õ wodi dijitaal ap…îw yi akyi w…î l…õgya mu. ∆êy…õ nhoma titiriw a wodi nnwuma nyinaa akyi ‚Äî akontaabu nhoma.</p><p>Saa l…õgya yi, …õfiri s…õ …õy…õ dijitaal, …õhia s…õ …õtena n‚Äôankasa wiase na …õw…î obi a …îhw…õ so.</p><p>Ka s…õ, te s…õ World of Warcraft no ara p…õ. Blizzard, mmarima a w…îy…õ…õ intan…õt so agodie no, w…î ‚Äúdijitaal l…õgya‚Äù a …õkyer…õ ogya nkrante a …õy…õ hyew a w…întaa nhu a …õw…î w…în nhyehy…õe no mu nyinaa. Enti, cool, obi te s…õ w…în betumi ahw…õ y…õn dijitaal ap…îw no so. Awesome ‚Äî y…õdii ho dwuma!</p><h3 id="…îhaw-ahorow" tabindex="-1"><a class="header-anchor" href="#…îhaw-ahorow" aria-hidden="true">#</a> ∆Ühaw ahorow</h3><p>∆Ühaw kakra w…î h…î:</p><ol><li><p>Na s…õ guy bi w…î Blizzard b…î…î pii nso …õ? Obetumi de dijitaal ap…îw kakra bi aka ne kari p…õ ho bere biara a …îp…õ!</p></li><li><p>∆ênte s…õ bere a na y…õte benkyi so saa da bi no p…õp…õ…õp…õ. Na …õy…õ me ne wo nkutoo saa bere no. S…õ wofa Blizzard mu a, …õte s…õ nea woretwe Wofa Tommy (obi a …îto so abi…õsa) afi as…õnnibea(mekaa s…õ …îy…õ …îtemmufo deda?) ama y…õn ab…înten benkyi nkitiahodi ahorow nyinaa. M…õy…õ d…õn atumi de me dijitaal ap…îw no ahy…õ wo nsa k…õk…õ, te s…õ, wunim‚Äî…îkwan a w…îtaa fa so no?</p></li></ol><blockquote><p>So …îkwan bi w…î h…î a y…õb…õfa so ay…õ y…õn park benkyi no ho mfonini k…õse, wo ne me nkutoo, aguadi w…î dijitaal kwan so? ∆ête s…õ nea …õy…õ den bi‚Ä¶</p></blockquote><h3 id="ano-aduru-no" tabindex="-1"><a class="header-anchor" href="#ano-aduru-no" aria-hidden="true">#</a> Ano aduru no</h3><p>Na s…õ y…õde saa l…õgya yi ‚Äî ma obiara nso …õ? S…õ anka l…õgya no b…õtena Blizzard k…împuta so no, …õb…õtena obiara k…împuta so. W…îb…õkyer…õw nnwuma a asi p…õn nyinaa, fi bere nyinaa, w…î dijitaal ap…îw no mu.</p><p>Wo ntumi nsisi no. Me ntumi nsoma wo dijitaal ap…îw a minni, efis…õ afei anka …õrenk…î sinke obiara …îw…î nhyehy…õe no mu. ∆êb…õy…õ nhyehy…õe a …õy…õ den s…õ wob…õboro so. Titiriw s…õ …õb…õy…õ…õ k…õse ankasa a.</p><p>Afei nso …õny…õ onipa baako na …îhw…õ so, enti menim s…õ obiara nni h…î a …îb…õtumi asi gyinae…õ k…õk…õ s…õ …îb…õma ne ho dijitaal ap…îw pii. Na w…îakyer…õkyer…õ nhyehy…õe no mmara mu dedaw w…î mfiase no. Na mmara ne nhyehy…õe no y…õ nea w…îabue ano. ∆êw…î h…î ma nnipa wonim nyansa no s…õ w…îb…õboa, ahw…õ so, ab…î ho ban, atu mp…în, na w…îahw…õ.</p><p>Wubetumi nso de wo ho ahy…õ saa n…õtw…õke yi mu na woay…õ sakra mu w…î l…õgya na woahw…õ ahu s…õ ne nyinaa hw…õ. ∆Ühaw no nti, wubetumi anya te s…õ dijitaal ap…îw aduonu anum s…õ akatua. Nokwarem no, …õno nkutoo ne …îkwan a wob…õfa so ay…õ dijitaal ap…îw pii w…î nhyehy…õe no mu.</p><h3 id="mey…õ…õ-nea-…õy…õ-mmer…õw-kakra" tabindex="-1"><a class="header-anchor" href="#mey…õ…õ-nea-…õy…õ-mmer…õw-kakra" aria-hidden="true">#</a> Mey…õ…õ nea …õy…õ mmer…õw kakra</h3><p>‚Ä¶ nanso saa nhyehy…õe a mekyer…õkyer…õ…õ mu no w…î h…î. W…îfr…õ no Bitcoin protocol. Na saa dijitaal ap…îw no ne <em>‚Äúbitcoins‚Äù</em> a …õw…î nhyehy…õe no mu. F…õ!</p><p>Enti, so wuhuu nea esii? D…õn na …îmanfo l…õgya no ma wotumi y…õ adwuma?</p><ol><li><p>∆êy…õ farebae a w…îabue ano wokae? W…îkyer…õkyer…õ…õ ap…îw dodow nyinaa mu w…î …îmanfo l…õgya mu w…î mfiase no. Minim dodow p…îtee a …õw…î h…î. W…î nhyehy…õe no mu no, menim s…õ w…îy…õ anohyeto(…õho y…õ na).</p></li><li><p>∆êy…õ farebae a w…îabue ano wokae? W…îkyer…õkyer…õ…õ ap…îw dodow nyinaa mu w…î …îmanfo l…õgya mu w…î mfiase no. Minim dodow p…îtee a …õw…î h…î. W…î nhyehy…õe no mu no, menim s…õ w…îy…õ anohyeto(…õho y…õ na).</p></li><li><p>Esiane s…õ …õy…õ …îmanfo l…õgya nti, na enhia W…îfa Tommy(…îbarima a …îto so abi…õsa) s…õ …îb…õ hw…õ s…õ mansisi, anaas…õ m…õy…õmfonini ahorow a …õboro so ama me ho, anaas…õ m…õsoma apple mprenu, anaa mpr…õnsa...</p><p>W…î nhyehy…õe no mu no, mprempren dijitaal ap…îw a w…îsesa no te s…õ honam fam ap…îw a w…îsesa no ara p…õ. Mprempren eye te s…õ nea wubehu s…õ honam fam ap…îw bi afi me nsa mu na ak…îhy…õ wo kotoku mu. Na te s…õ nea na …õte w…î ab…înten so benkyi so no, na nnipa baanu p…õ na w…îsesa w…în ho w…în ho. Me ne wo ‚Äî na yenhia W…îfa Tommy w…î h…î na ama ay…õ nea …õfata.</p></li></ol><p>∆Ükwan foforo so no, …õy…õ n‚Äôade te s…õ honam fam ade.</p><p>Nanso wunim nea …õy…õ d…õ? ∆êda so ara y…õ dijitaal. Seesei yebetumi adi ap…îw apem biako, anaa ap…îw …îpepem biako, anaa mpo ap…îw .0000001 ho dwuma. Metumi de amena denam b…îtn bi a wob…õb…î so, na meda so ara tumi de gu wo dijitaal kotoku mu s…õ na mew…î Nicaragua na wo nso wow…î New York nyinaa a.</p><p>Metumi mpo ama dijitaal nne…õma afoforo atra dijitaal ap…îw yi atifi! ∆êy…õ dijitaal w…î ne nyinaa akyi. Ebia metumi de ns…õm bi abata ho ‚Äî dijitaal nkyer…õwde. Anaas…õ ebia metumi de nne…õma a …õho hia k…õse abata ho; te s…õ ka s…õ k…întraagye, anaa stock adansedi krataa, anaa ID krataa...</p><p>Enti eyi y …õ k…õse! ∆Ükwan b…õn so na …õs…õ s…õ y…õfa saa ‚Äúdijitaal ap…îw‚Äù yi ho dwuma anaas…õ y…õbu no s…õ …õsom bo? W…în ho w…î mfaso koraa …õnte saa?</p><p>Wi…õ, nnipa pii regye akyinnye w…î ho mprempren. Akyinnyegye w…î eyi ne saa sikas…õm sukuu no ntam. W…î amammuifo ntam. W…î nhyehy…õey…õfo ntam. Nanso, ntie w…în nyinaa. Nnipa binom y…õ anifere. W…îde ns…õm a …õnte…õ ma ebinom. Ebinom ka s…õ nhyehy…õe no bo y…õ den, ebinom ka s…õ nokwarem no …õsom bo hwee. Guy bi de n…îma a …õy…õ den too h…î ankasa: $1,300 w…î ap…îw biara ho. Ebinom se …õy…õ digital gold, ebinom ka s…õ …õy…õ sika. Afoforo ka s…õ w…îte s…õ tulips ara kwa. Nnipa binom ka s…õ …õb…õsesa wiase, ebinom ka s…õ …õy…õ ade a aba so ara kwa.</p><p>Mew…î m‚Äôankasa m‚Äôadwene w…î ho.</p><p>∆êno y…õ as…õm a …õfa bere foforo ho nanso. Nanso kid, seesei wunim Bitcoin ho ns…õm pii sen dodow no ara.</p><h4 id="kamfo-akenkan-w…îay…õ-no-foforo-2017" tabindex="-1"><a class="header-anchor" href="#kamfo-akenkan-w…îay…õ-no-foforo-2017" aria-hidden="true">#</a> Kamfo Akenkan (W…îay…õ no foforo 2017)</h4>',47),r={href:"https://medium.com/@mariabustillos/wo-nte-bitcoin-ase-efis%C9%9B-wo-susuw-s%C9%9B-sika-y%C9%9B-nokware-5aef45b8e952?source=linkShare-2d6f142ff3cc-1512362100",target:"_blank",rel:"noopener noreferrer"},y=(0,o.Uk)("‚ÄúWo Nte Bitcoin ase Efis…õ Wosusuw s…õ Sika Y…õ Ankasa‚Äù"),h={href:"https://www.freecodecamp.org/news/explain-bitcoin-like-im-five-73b4257ac833/undefined",target:"_blank",rel:"noopener noreferrer"},d=(0,o.Uk)("Maria Bustillos"),p=(0,o.Uk)(" na …îkyer…õwee y…õ akenkan pa a edi akyi."),k=(0,o.Uk)("Wubetumi nso akenkan pii afa "),u={href:"https://medium.freecodecamp.org/smart-apam-ma-ay%C9%9By%C9%9Bde-a1ba1e0b9575?fibea=linkKy%C9%9B-2d6f142ff3cc-1512086124",target:"_blank",rel:"noopener noreferrer"},b=(0,o.Uk)("Ethereum ne Smart Contracts ho w…î ha"),l=(0,o.Uk)(". Di d…õ!"),f={},c=(0,e(83744).Z)(f,[["render",function(a,n){const e=(0,o.up)("OutboundLink"),f=(0,o.up)("LanguageDropdown");return(0,o.wg)(),(0,o.iD)(o.HY,null,[i,(0,o._)("p",null,[s,(0,o._)("a",m,[w,(0,o.Wm)(e)])]),(0,o.Wm)(f),t,(0,o._)("p",null,[(0,o._)("a",r,[y,(0,o.Wm)(e)]),(0,o._)("a",h,[d,(0,o.Wm)(e)]),p]),(0,o._)("p",null,[k,(0,o._)("a",u,[b,(0,o.Wm)(e)]),l])],64)}]])},83744:(a,n)=>{n.Z=(a,n)=>{const e=a.__vccOpts||a;for(const[a,o]of n)e[a]=o;return e}}}]);